diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..f138067c1b69 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2263,6 +2263,35 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // sub(smin(add like 1, Y), smin(X, Y)) -> zext(X < Y)
+  // sub(umin(add like 1, Y), umin(X, Y)) -> zext(X < Y)
+  auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0);
+  if (MinMax0 && Op0->hasOneUse()) {
+    Value *X1, *Y1;
+    // Handle smin with nsw add or disjoint or
+    if (MinMax0->getIntrinsicID() == Intrinsic::smin &&
+        match(MinMax0, m_Intrinsic<Intrinsic::smin>(
+                           m_NSWAddLike(m_Value(X1), m_One()), m_Value(Y1)))) {
+      auto *MinMax1 = dyn_cast<MinMaxIntrinsic>(Op1);
+      if (MinMax1 && MinMax1->getIntrinsicID() == Intrinsic::smin &&
+          match(MinMax1, m_OneUse(m_Intrinsic<Intrinsic::smin>(m_Specific(X1), m_Specific(Y1))))) {
+        Value *Cmp = Builder.CreateICmp(ICmpInst::ICMP_SLT, X1, Y1);
+        return ZExtInst::CreateZExtOrBitCast(Cmp, Ty);
+      }
+    }
+    // Handle umin with nuw add or disjoint or
+    if (MinMax0->getIntrinsicID() == Intrinsic::umin &&
+        match(MinMax0, m_Intrinsic<Intrinsic::umin>(
+                           m_NUWAddLike(m_Value(X1), m_One()), m_Value(Y1)))) {
+      auto *MinMax1 = dyn_cast<MinMaxIntrinsic>(Op1);
+      if (MinMax1 && MinMax1->getIntrinsicID() == Intrinsic::umin &&
+          match(MinMax1, m_OneUse(m_Intrinsic<Intrinsic::umin>(m_Specific(X1), m_Specific(Y1))))) {
+        Value *Cmp = Builder.CreateICmp(ICmpInst::ICMP_ULT, X1, Y1);
+        return ZExtInst::CreateZExtOrBitCast(Cmp, Ty);
+      }
+    }
+  }
+
   return nullptr;
 }

